me":"p","properties":{},"children":[{"type":"text","value":"不要把 "},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":".env"}]},{"type":"text","value":"、数据库密码、模型\nKey、"},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"MODEL_CONFIG_ENCRYPTION_KEY"}]},{"type":"text","value":"、"},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"AGENT_CONFIG_CONTROL_KEY"}]},{"type":"text","value":"、初始管理员密码或\nTOTP 恢复码提交到 Git，也不要写入日志或工单。"}]}]},{"type":"text","value":"\n"},{"type":"element","tagName":"h2","properties":{"id":"doc-content-当前能力边界"},"children":[{"type":"text","value":"当前能力边界"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"后台已经支持 OpenAI、Anthropic、Google、Qwen / DashScope、DeepSeek 和 MiniMax 的云模型配置。Skill、Knowledge、Tools/网页操作和本地算力卡片目前只是诚实的 roadmap 入口，不会加载能力、探测本地服务或发起安装请求。"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"设计参考 Agno 官方 "},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/agent-os/config"},"children":[{"type":"text","value":"AgentOS Configuration"}]},{"type":"text","value":"、"},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/skills/overview"},"children":[{"type":"text","value":"Skills"}]},{"type":"text","value":"、"},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/skills/loading-skills"},"children":[{"type":"text","value":"Loading Skills"}]},{"type":"text","value":"、"},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/tools/agent"},"children":[{"type":"text","value":"Tools"}]},{"type":"text","value":"、"},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/agent-os/features/knowledge-management"},"children":[{"type":"text","value":"Knowledge"}]},{"type":"text","value":"、"},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/models/providers/local/ollama/overview"},"children":[{"type":"text","value":"Ollama"}]},{"type":"text","value":"、"},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/models/providers/local/vllm/overview"},"children":[{"type":"text","value":"vLLM"}]},{"type":"text","value":" 和 "},{"type":"element","tagName":"a","properties":{"href":"https://docs.agno.com/models/providers/openai-like"},"children":[{"type":"text","value":"OpenAI-compatible Models"}]},{"type":"text","value":"。本仓库行为以 "},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"apps/agent/uv.lock"}]},{"type":"text","value":" 锁定的 Agno "},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"2.7.2"}]},{"type":"text","value":" 和本地测试为准，不假设最新版文档 API 已存在。"}]}]},"toc":[{"id":"doc-content-推荐目录","title":"推荐目录","depth":2},{"id":"doc-content-部署步骤","title":"部署步骤","depth":2},{"id":"doc-content-准备基础配置和独立-secret","title":"准备基础配置和独立 Secret","depth":3},{"id":"doc-content-初始化平台agentos-和模型控制数据库","title":"初始化平台、AgentOS 和模型控制数据库","depth":3},{"id":"doc-content-选择部署级开关","title":"选择部署级开关","depth":3},{"id":"doc-content-启动服务并检查健康状态","title":"启动服务并检查健康状态","depth":3},{"id":"doc-content-完成第一次后台激活","title":"完成第一次后台激活","depth":3},{"id":"doc-content-启动与恢复语义","title":"启动与恢复语义","depth":2},{"id":"doc-content-回滚","title":"回滚","depth":2},{"id":"doc-content-key-与-endpoint-运维","title":"Key 与 Endpoint 运维","depth":2},{"id":"doc-content-当前能力边界","title":"当前能力边界","depth":2}]}}'::jsonb
