-- Document seed: upgrade
DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM "content"
    WHERE ("id" = '019f79c8-9a00-7000-8000-000000000003'::uuid OR "slug" = 'upgrade')
      AND NOT ("id" = '019f79c8-9a00-7000-8000-000000000003'::uuid AND "slug" = 'upgrade')
  ) OR EXISTS (
    SELECT 1 FROM "content"
    WHERE "id" = '019f79c8-9a00-7000-8000-000000000003'::uuid AND "slug" = 'upgrade'
      AND ("type" IS DISTINCT FROM 'document'
        OR "title" IS DISTINCT FROM '升级手册'
        OR "summary" IS DISTINCT FROM '以可回滚、可审计的方式升级平台版本和数据库结构。'
        OR "body" IS DISTINCT FROM '{"format":"safe-markdown-v1","source":"## 升级原则\n\n先备份，再迁移；先验证，再切流。应用版本和数据库迁移必须能够对应到同一个发布版本。\n\n:::steps\n\n### 阅读 Release Note\n\n确认破坏性变更、环境要求、权限变化和需要手动处理的数据迁移。\n\n### 备份并执行迁移\n\n在维护窗口创建数据库备份和当前镜像快照，执行迁移后记录迁移版本。\n\n### 灰度验证\n\n优先验证登录、文档、Agent 会话、管理员后台和健康检查，再扩大流量。\n\n:::\n\n:::callout{type=\"important\"}\n升级前应明确回滚条件和负责人；不要只依赖容器重启作为回滚方案。\n:::\n","checksum":"f77bdd3eee2ed93f82d5c3a8f84b16f730aa60fa1f23b5525eb0db55bf5c71f9","navigation":{"label":"升级手册","code":"UPGRADE","position":30},"renderModel":{"version":1,"root":{"type":"root","children":[{"type":"element","tagName":"h2","properties":{"id":"doc-content-升级原则"},"children":[{"type":"text","value":"升级原则"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"先备份，再迁移；先验证，再切流。应用版本和数据库迁移必须能够对应到同一个发布版本。"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"document-steps","properties":{},"children":[{"type":"element","tagName":"h3","properties":{"id":"doc-content-阅读-release-note"},"children":[{"type":"text","value":"阅读 Release Note"}]},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"确认破坏性变更、环境要求、权限变化和需要手动处理的数据迁移。"}]},{"type":"element","tagName":"h3","properties":{"id":"doc-content-备份并执行迁移"},"children":[{"type":"text","value":"备份并执行迁移"}]},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"在维护窗口创建数据库备份和当前镜像快照，执行迁移后记录迁移版本。"}]},{"type":"element","tagName":"h3","properties":{"id":"doc-content-灰度验证"},"children":[{"type":"text","value":"灰度验证"}]},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"优先验证登录、文档、Agent 会话、管理员后台和健康检查，再扩大流量。"}]}]},{"type":"text","value":"\n"},{"type":"element","tagName":"document-callout","properties":{"dataCalloutType":"important"},"children":[{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"升级前应明确回滚条件和负责人；不要只依赖容器重启作为回滚方案。"}]}]}]},"toc":[{"id":"doc-content-升级原则","title":"升级原则","depth":2},{"id":"doc-content-阅读-release-note","title":"阅读 Release Note","depth":3},{"id":"doc-content-备份并执行迁移","title":"备份并执行迁移","depth":3},{"id":"doc-content-灰度验证","title":"灰度验证","depth":3}]}}'::jsonb
        OR "status" IS DISTINCT FROM 'published'::"content_status"
        OR "revision" IS DISTINCT FROM 1
        OR "row_version" IS DISTINCT FROM 1
        OR "published_revision" IS DISTINCT FROM 1
        OR "archived_at" IS NOT NULL
        OR "deleted_at" IS NOT NULL)
  ) OR EXISTS (
    SELECT 1 FROM "content_revisions"
    WHERE ("id" = '019f79c8-9a00-7000-9000-000000000003'::uuid OR ("content_id" = '019f79c8-9a00-7000-8000-000000000003'::uuid AND "revision" = 1))
      AND ("id" IS DISTINCT FROM '019f79c8-9a00-7000-9000-000000000003'::uuid
        OR "content_id" IS DISTINCT FROM '019f79c8-9a00-7000-8000-000000000003'::uuid
        OR "revision" IS DISTINCT FROM 1
        OR "slug" IS DISTINCT FROM 'upgrade'
        OR "title" IS DISTINCT FROM '升级手册'
        OR "summary" IS DISTINCT FROM '以可回滚、可审计的方式升级平台版本和数据库结构。'
        OR "body" IS DISTINCT FROM '{"format":"safe-markdown-v1","source":"## 升级原则\n\n先备份，再迁移；先验证，再切流。应用版本和数据库迁移必须能够对应到同一个发布版本。\n\n:::steps\n\n### 阅读 Release Note\n\n确认破坏性变更、环境要求、权限变化和需要手动处理的数据迁移。\n\n### 备份并执行迁移\n\n在维护窗口创建数据库备份和当前镜像快照，执行迁移后记录迁移版本。\n\n### 灰度验证\n\n优先验证登录、文档、Agent 会话、管理员后台和健康检查，再扩大流量。\n\n:::\n\n:::callout{type=\"important\"}\n升级前应明确回滚条件和负责人；不要只依赖容器重启作为回滚方案。\n:::\n","checksum":"f77bdd3eee2ed93f82d5c3a8f84b16f730aa60fa1f23b5525eb0db55bf5c71f9","navigation":{"label":"升级手册","code":"UPGRADE","position":30},"renderModel":{"version":1,"root":{"type":"root","children":[{"type":"element","tagName":"h2","properties":{"id":"doc-content-升级原则"},"children":[{"type":"text","value":"升级原则"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"先备份，再迁移；先验证，再切流。应用版本和数据库迁移必须能够对应到同一个发布版本。"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"document-steps","properties":{},"children":[{"type":"element","tagName":"h3","properties":{"id":"doc-content-阅读-release-note"},"children":[{"type":"text","value":"阅读 Release Note"}]},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"确认破坏性变更、环境要求、权限变化和需要手动处理的数据迁移。"}]},{"type":"element","tagName":"h3","properties":{"id":"doc-content-备份并执行迁移"},"children":[{"type":"text","value":"备份并执行迁移"}]},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"在维护窗口创建数据库备份和当前镜像快照，执行迁移后记录迁移版本。"}]},{"type":"element","tagName":"h3","properties":{"id":"doc-content-灰度验证"},"children":[{"type":"text","value":"灰度验证"}]},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"优先验证登录、文档、Agent 会话、管理员后台和健康检查，再扩大流量。"}]}]},{"type":"text","value":"\n"},{"type":"element","tagName":"document-callout","properties":{"dataCalloutType":"important"},"children":[{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"升级前应明确回滚条件和负责人；不要只依赖容器重启作为回滚方案。"}]}]}]},"toc":[{"id":"doc-content-升级原则","title":"升级原则","depth":2},{"id":"doc-content-阅读-release-note","title":"阅读 Release Note","depth":3},{"id":"doc-content-备份并执行迁移","title":"备份并执行迁移","depth":3},{"id":"doc-content-灰度验证","title":"灰度验证","depth":3}]}}'::jsonb
        OR "created_by" IS NOT NULL
        OR "created_at" IS DISTINCT FROM '2026-07-19T00:00:00.000Z'::timestamptz)
  ) OR EXISTS (
    SELECT 1 FROM "content_routes"
    WHERE "slug" = 'upgrade'
      AND ("content_id" IS DISTINCT FROM '019f79c8-9a00-7000-8000-000000000003'::uuid OR "state" = 'alias')
  ) THEN
    RAISE EXCEPTION 'DOCUMENT_SEED_IDENTITY_COLLISION:upgrade' USING ERRCODE = '23505';
  END IF;
END;
