-- Document seed: api
DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM "content"
    WHERE ("id" = '019f79c8-9a00-7000-8000-000000000005'::uuid OR "slug" = 'api')
      AND NOT ("id" = '019f79c8-9a00-7000-8000-000000000005'::uuid AND "slug" = 'api')
  ) OR EXISTS (
    SELECT 1 FROM "content"
    WHERE "id" = '019f79c8-9a00-7000-8000-000000000005'::uuid AND "slug" = 'api'
      AND ("type" IS DISTINCT FROM 'document'
        OR "title" IS DISTINCT FROM 'API 文档'
        OR "summary" IS DISTINCT FROM '平台公开接口的调用约定、鉴权方式和错误处理边界。'
        OR "body" IS DISTINCT FROM '{"format":"safe-markdown-v1","source":"## 接口约定\n\nAPI 统一使用 HTTPS 和 JSON。需要登录的接口通过会话 Cookie 或服务端 API Key 鉴权，响应错误包含稳定的 `code` 和可读的 `message`。\n\n健康检查示例：`GET /api/health/ready`，请求头使用 `Accept: application/json`，成功响应包含 `status: ready`。\n\n## 鉴权和权限\n\n客户、内部员工和管理员使用不同的访问边界。服务端必须再次校验角色与权限，不能只依赖前端隐藏菜单。\n\n:::callout{type=\"info\"}\nAgent、知识库和模型网关接口的详细 schema\n会随对应模块稳定后补齐；当前页面先作为统一入口和契约索引。\n:::\n","checksum":"544aacad1561d60ebd9e1d87c8f89555139c436f19f7ae0a57cb99822ca64e8d","navigation":{"label":"API 文档","code":"API","position":50},"renderModel":{"version":1,"root":{"type":"root","children":[{"type":"element","tagName":"h2","properties":{"id":"doc-content-接口约定"},"children":[{"type":"text","value":"接口约定"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"API 统一使用 HTTPS 和 JSON。需要登录的接口通过会话 Cookie 或服务端 API Key 鉴权，响应错误包含稳定的 "},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"code"}]},{"type":"text","value":" 和可读的 "},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"message"}]},{"type":"text","value":"。"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"健康检查示例："},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"GET /api/health/ready"}]},{"type":"text","value":"，请求头使用 "},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"Accept: application/json"}]},{"type":"text","value":"，成功响应包含 "},{"type":"element","tagName":"code","properties":{},"children":[{"type":"text","value":"status: ready"}]},{"type":"text","value":"。"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"h2","properties":{"id":"doc-content-鉴权和权限"},"children":[{"type":"text","value":"鉴权和权限"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"客户、内部员工和管理员使用不同的访问边界。服务端必须再次校验角色与权限，不能只依赖前端隐藏菜单。"}]},{"type":"text","value":"\n"},{"type":"element","tagName":"document-callout","properties":{"dataCalloutType":"info"},"children":[{"type":"element","tagName":"p","properties":{},"children":[{"type":"text","value":"Agent、知识库和模型网关接口的详细 schema\n会随对应模块稳定后补齐；当前页面先作为统一入口和契约索引。"}]}]}]},"toc":[{"id":"doc-content-接口约定","title":"接口约定","depth":2},{"id":"doc-content-鉴权和权限","title":"鉴权和权限","depth":2}]}}'::jsonb
        OR "status" IS DISTINCT FROM 'published'::"content_status"
        OR "revision" IS DISTINCT FROM 1
