        OR "archived_at" IS NOT NULL
        OR "deleted_at" IS NOT NULL)
  ) OR EXISTS (
    SELECT 1 FROM "content_revisions"
    WHERE ("id" = '019f79c8-9a00-7000-9000-000000000005'::uuid OR ("content_id" = '019f79c8-9a00-7000-8000-000000000005'::uuid AND "revision" = 1))
